feed:
	{{ config.title }}
	{%- if config.description %}
	{{ config.description }}
	{%- endif %}


  {% if last_updated is defined %}
	{{ last_updated | date(format="%+") }}
	{% endif %}
	{{ feed_url | safe }}
	{%- for page in pages %}

		{{ page.title }}
		{{ page.date | date(format="%+") }}
		{{ page.updated | default(value=page.date) | date(format="%+") }}

		{{ page.permalink | safe }}
    {% if page.summary %}
    {{ page.summary }}
    {% endif %}
		{{ page.content }}

	{%- endfor %}
